// Use cross-validation for small datasets, train/test split for larger ones
var rowCount = (int)data.GetColumn<bool>("Label").Count();
if (rowCount >= 20)
{
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);
    var model = pipeline.Fit(split.TrainSet);
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
    Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
else
{
    Console.WriteLine($"Small dataset ({rowCount} rows) — using cross-validation.");
    var cvResults = mlContext.BinaryClassification.CrossValidate(data, pipeline, numberOfFolds: Math.Min(5, rowCount), labelColumnName: "Label");
    var avgAccuracy = cvResults.Average(r => r.Metrics.Accuracy);
    Console.WriteLine($"Cross-validation avg accuracy: {avgAccuracy:F4}");
}

// Train final model on all data
var trainedModel = pipeline.Fit(data);

